            if(K == 0) break;

            int w, a, b;

            tie(w, a, b) = tp;

            if(find(a, b) && find(b, a)) {

                K--;

                ans += w;

                used[a].insert(b);

                used[b].insert(a);

            }

        }

        return ans;

    }

}





