						tq.clear();

						break;

					}

					a[tx][ty] = 0;

					tq.push_back(P(tx, ty));

				}

			}

		}

		q = tq, sol = tsol;

	}

	cout << (res ? "Yes" : "No") << endl;

	return 0;

}

